import{_ as i,o as r,c as o,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Sponsored Social (publisher)","description":"","frontmatter":{"title":"Sponsored Social (publisher)"},"headers":[],"relativePath":"docs/fr/publishers/sponsored-social/index.md","filePath":"docs/fr/publishers/sponsored-social/index.md"}'),s={name:"docs/fr/publishers/sponsored-social/index.md"};function d(t,e,n,p,l,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="sponsored-social" tabindex="-1">Sponsored Social <a class="header-anchor" href="#sponsored-social" aria-label="Permalink to &quot;Sponsored Social&quot;">​</a></h1><p>Monétisez votre audience sociale (Instagram, TikTok) sans polluer votre ligne éditoriale grâce aux &quot;Partnership Ads&quot;.</p><div><a href="guide" class="btn btn-primary">Voir le Guide de Publication</a></div><hr><h2>Le principe : &quot;Partnership Ads&quot;</h2><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;margin-bottom:40px;"><p>Contrairement à l&#39;influence classique, nous utilisons la <strong>Sponsorisation</strong>.</p><ul><li>Vous postez un contenu qualitatif (en partenariat avec une marque).</li><li>L&#39;Annonceur investit son propre budget média pour diffuser <strong>votre</strong> post auprès de milliers de nouvelles personnes.</li></ul></div><h2>Vos Avantages</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;width:100%;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>💰 Rémunération</h3><p>Vous êtes payé pour la création du contenu et/ou sa publication.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>📈 Croissance Gratuite</h3><p>L&#39;annonceur paie pour montrer <strong>VOTRE profil</strong> à une large audience. C&#39;est de l&#39;acquisition d&#39;abonnés gratuite pour vous.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>✨ Qualité Préservée</h3><p>Comme le post est amplifié en média (Dark post ou Boost), pas besoin de spammer votre feed organique.</p></div></div><h2>Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">⚙️</div><div><h3>Setup Simplifié</h3><p>La configuration des droits publicitaires sur Meta ou TikTok est un cauchemar. Nous vous guidons pas à pas pour lier les comptes sans erreur.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🤝</div><div><h3>Marques Premium</h3><p>Collaborez avec des annonceurs vérifiés qui cherchent de la performance long terme, pas des &quot;coups&quot; d&#39;un jour.</p></div></div></div>',10)])])}const g=i(s,[["render",d]]);export{v as __pageData,g as default};
